`YearCode`) `a` on(((`f`.`pacsid` = `a`.`pacsid`) and (`f`.`YearCode` = `a`.`YearCode`)))) group by `p`.`pacsid`), `faAccountLossProfit` as (select `a`.`pacsid` AS `pacsid`,`a`.`OBCreditAmount` AS `profitamt`,`a`.`OBDebitAmount` AS `lossamt`,sum((case when (`a`.`OBCreditAmount` > 0) then 1 else 0 end)) AS `profit`,sum((case when (`a`.`OBDebitAmount` > 0) then 1 else 0 end)) AS `loss` from (`fa_accountdetails` `a` join `fa_ledger` `l` on(((`a`.`LedgerPkey` = `l`.`LedgerId`) and (`l`.`ParentLedgerCode` = 189)))) group by `a`.`pacsid`,`profitamt`,`lossamt`), `repaymentdetails` as (select `ln_productdetails`.`pacid` AS `pacid`,sum((case when (`ln_productdetails`.`RepaymentTypeId` = '1') then 1 else 0 end)) AS `EquatedInstallment`,sum((case when (`ln_productdetails`.`RepaymentTypeId` = '2') then 1 else 0 end)) AS `EquatedPrincipal`,sum((case when (`ln_productdetails`.`RepaymentTypeId` = '3') then 1 else 0 end)) AS `BulletSimple`,sum((case when (`ln_productdetails`.`RepaymentTypeId` = '4') then 1 else 0 end)) AS `BulletCompound` from `ln_productdetails` group by `ln_productdetails`.`pacid`), `newmembershipdetails` as (select `cm`.`pacsid` AS `pacsid`,json_objectagg(concat(year(`ref`.`DateValue`),'-',convert(lpad(month(`ref`.`DateValue`),2,'0') using utf8mb4)),json_object('TotalAdmissions',ifnull(`ccp_grouped`.`TotalAdmissions`,0))) AS `AdmissionsData` from ((`cm_pacsdetails` `cm` join (select date_format((curdate() - interval `numbers`.`seq` month),'%Y-%m-01') AS `DateValue` from (select 0 AS `seq` union all select 1 AS `1` union all select 2 AS `2` union all select 3 AS `3` union all select 4 AS `4` union all select 5 AS `5` union all select 6 AS `6` union all select 7 AS `7` union all select 8 AS `8` union all select 9 AS `9` union all select 10 AS `10` union all select 11 AS `11`) `numbers` order by `DateValue`) `ref`) left join (select `ccp`.`pacsid` AS `pacsid`,year(`ccp`.`AdmissionDate`) AS `AdmissionYear`,month(`ccp`.`AdmissionDate`) AS `AdmissionMonth`,count(0) AS