nQuarter`)))) group by `cm`.`pacsid`), `InterestExpense` as (with `DepositLedgers` as (select `fa_ledger`.`LedgerId` AS `LedgerId` from `fa_ledger` where (`fa_ledger`.`ParentLedgerCode` = 119) union select `fa_ledger`.`LedgerId` AS `LedgerId` from `fa_ledger` where (`fa_ledger`.`LedgerId` = 119)), `BorrowingLedgers` as (select `fa_ledger`.`LedgerId` AS `LedgerId` from `fa_ledger` where (`fa_ledger`.`ParentLedgerCode` in (120,121,122)) union select `fa_ledger`.`LedgerId` AS `LedgerId` from `fa_ledger` where (`fa_ledger`.`LedgerId` in (120,121,122))), `InterestDeposits` as (select `v`.`pacsid` AS `pacsid`,sum((`v`.`Debit` - `v`.`Credit`)) AS `InterestExpenseDeposits` from (`fa_voucherdetails` `v` join `DepositLedgers` `l` on((`v`.`LedgerCode` = `l`.`LedgerId`))) group by `v`.`pacsid`), `InterestBorrowings` as (select `v`.`pacsid` AS `pacsid`,sum((`v`.`Debit` - `v`.`Credit`)) AS `InterestExpenseBorrowings` from (`fa_voucherdetails` `v` join `BorrowingLedgers` `l` on((`v`.`LedgerCode` = `l`.`LedgerId`))) group by `v`.`pacsid`) select `cpd`.`pacsid` AS `pacsid`,coalesce(`d`.`InterestExpenseDeposits`,0) AS `InterestExpenseDeposits`,coalesce(`b`.`InterestExpenseBorrowings`,0) AS `InterestExpenseBorrowings` from ((`cm_pacsdetails` `cpd` left join `InterestDeposits` `d` on((`cpd`.`pacsid` = `d`.`pacsid`))) left join `InterestBorrowings` `b` on((`cpd`.`pacsid` = `b`.`pacsid`)))), `OtherExpenses` as (with `RelevantLedgers` as (select `fa_ledger`.`LedgerId` AS `LedgerId` from `fa_ledger` where (`fa_ledger`.`ParentLedgerCode` in (124,125,126,127,128,129,130,131,133,134,135,138)) union select `fl`.`LedgerId` AS `LedgerId` from (`fa_ledger` `fl` join `fa_ledger` `parent` on((`fl`.`ParentLedgerCode` = `parent`.`LedgerId`))) where (`parent`.`ParentLedgerCode` in (124,125,126,127,128,129,130,131,133,134,135,138))) select `cpd`.`pacsid` AS `pacsid`,coalesce(sum((`v`.`Debit` - `v`.`Credit`)),0) AS `OtherExpenses` from (`cm_pacsdetails` `cpd` left join `fa_voucherdetails` `v` on(((`cpd`