TotalDemandInterest`) - (`Summary`.`TotalCollectedPrincipal` + `Summary`.`TotalCollectedInterest`)) AS `LR_DemandAmt`,coalesce((((`Summary`.`TotalCollectedPrincipal` + `Summary`.`TotalCollectedInterest`) / nullif(((`Summary`.`TotalDemandPrincipal` + `Summary`.`TotalDemandInterest`) - (`Summary`.`TotalCollectedPrincipal` + `Summary`.`TotalCollectedInterest`)),0)) * 100),0) AS `LR_RecoveryRate`,(case when (((`Summary`.`TotalCollectedPrincipal` + `Summary`.`TotalCollectedInterest`) = (`Summary`.`TotalDemandPrincipal` + `Summary`.`TotalDemandInterest`)) and (`Summary`.`DueDate` < curdate())) then 'Fully Paid Before Due Date' else 'Not Fully Paid' end) AS `LR_PaymentStatus` from `Summary`), `TotalAssert` as (select `SubQuery`.`pacsid` AS `pacsid`,group_concat(concat(`SubQuery`.`CategoryName`,'=',`SubQuery`.`CategoryCount`) order by `SubQuery`.`CategoryName` ASC separator ', ') AS `CategoryDetails` from (select `a`.`pacsid` AS `pacsid`,`b`.`CategoryName` AS `CategoryName`,count(0) AS `CategoryCount` from (`ast_itemmaster` `a` join `ast_categorymaster` `b` on((`a`.`CategoryID` = `b`.`CategoryID`))) group by `a`.`pacsid`,`b`.`CategoryName`) `SubQuery` group by `SubQuery`.`pacsid`), `PigmyDeposit` as (with `DailyTransactions` as (select `pgm_dailytransactions`.`PigmySlNoPKey` AS `PigmySlNoPKey`,sum(`pgm_dailytransactions`.`InstallmentAmount`) AS `TotalInstallmentAmount` from `pgm_dailytransactions` group by `pgm_dailytransactions`.`PigmySlNoPKey`), `ClosureForeclosure` as (select `pgm_pigmyclosureforeclosure`.`PigmyAccNoFkey` AS `PigmyAccNoFkey`,sum(`pgm_pigmyclosureforeclosure`.`InstallmentAmountCollected`) AS `TotalInstallmentAmountCollected` from `pgm_pigmyclosureforeclosure` group by `pgm_pigmyclosureforeclosure`.`PigmyAccNoFkey`) select `pgm_app`.`pacsid` AS `pacsid`,count(0) AS `pigmydepCount`,coalesce(sum((`dt`.`TotalInstallmentAmount` - `cf`.`TotalInstallmentAmountCollected`)),0) AS `OutStandingAmount` from ((`pgm_applicationdetails` `pgm_app` left join `DailyTransac